function Chart() {
    const { incomes, expenses } = useGlobalContext();

    // Format income and expense dates separately
    const incomeEntries = incomes.map((inc) => ({
        date: dateFormat(inc.date),
        amount: inc.amount
    }));

    const expenseEntries = expenses.map((exp) => ({
        date: dateFormat(exp.date),
        amount: exp.amount
    }));

    // Prepare income data and labels
    const incomeData = incomeEntries.map(entry => entry.amount);
    const incomeLabels = incomeEntries.map(entry => entry.date);

    // Prepare expense data and labels
    const expenseData = expenseEntries.map(entry => entry.amount);
    const expenseLabels = expenseEntries.map(entry => entry.date);

    const data = {
        labels: [...new Set([...incomeLabels, ...expenseLabels])].sort(),
        datasets: [
            {
                label: 'Income',
                data: incomeLabels.map(label => {
                    const incomeEntry = incomeEntries.find(entry => entry.date === label);
                    return incomeEntry ? incomeEntry.amount : null; // Use null to avoid plotting on missing dates
                }),
                backgroundColor: 'green',
                tension: 0.2,
            },
            {
                label: 'Expenses',
                data: expenseLabels.map(label => {
                    const expenseEntry = expenseEntries.find(entry => entry.date === label);
                    return expenseEntry ? expenseEntry.amount : null; // Use null to avoid plotting on missing dates
                }),
                backgroundColor: 'red',
                tension: 0.2,
            }
        ]
    };

    return (
        <ChartStyled>
            <Line data={data} />
        </ChartStyled>
    );
}


const ChartStyled = styled.div`
    background: #FCF6F9;
    border: 2px solid #FFFFFF;
    box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);
    padding: 1rem;
    border-radius: 20px;
    height: 100%;
`;

export default Chart
